def checkAdminPassword(password):
    if len(password) < 12:
        return False
    if not re.search(r'[A-Z]', password):
        return False
    if not re.search(r'[a-z]', password):
        return False
    if not re.search(r'[0-9]', password):
        return False
    if not re.search(r'[!@#$%^&*()_+-=[]{}|;":\'<>,.?/~`]', password):
        return False
    common_passwords = {'password', '123456', 'admin', 'letmein', 'welcome', '123456789', 'qwerty', 'abc123', 'password123', '123123', '000000', '12345', '654321', '555555', '1234567890', '123321', '12345678', '1234567', '123456', '12345', '1234', '123'}
    if password in common_passwords:
        return False
    return True

